using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver(),
    WriteIndented = true
};

// ──────────────────────────────────────────────
// 1. GetTypeInfo<T>()  →  returns JsonTypeInfo<T> directly (no cast needed)
// ──────────────────────────────────────────────
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Strongly-typed metadata for Person:");
Console.WriteLine($"  Type  : {personInfo.Type}");
Console.WriteLine($"  Kind  : {personInfo.Kind}");
Console.WriteLine($"  Props : {personInfo.Properties.Count}");

// Round-trip via the typed metadata
var json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"  JSON  : {json}");
var back = JsonSerializer.Deserialize(json, personInfo);
Console.WriteLine($"  Deser : {back}");
Console.WriteLine();

// ──────────────────────────────────────────────
// 2. TryGetTypeInfo()  →  probe without throwing
// ──────────────────────────────────────────────

// 2a. Type the resolver knows about
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
    Console.WriteLine($"TryGetTypeInfo(Person)  → found  (Type={found!.Type.Name})");
else
    Console.WriteLine("TryGetTypeInfo(Person)  → NOT found");

// 2b. Type the resolver does NOT know about (use a resolver that only handles Person)
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new LimitedResolver()
};

if (limited.TryGetTypeInfo(typeof(string), out _))
    Console.WriteLine("TryGetTypeInfo(string)  → found");
else
    Console.WriteLine("TryGetTypeInfo(string)  → NOT found  (resolver doesn't handle it)");

// ──────────────────────────────────────────────
// Supporting types
// ──────────────────────────────────────────────
public record Person(string Name, int Age);

/// <summary>A resolver that only provides metadata for <see cref="Person"/>.</summary>
file class LimitedResolver : IJsonTypeInfoResolver
{
    private static readonly DefaultJsonTypeInfoResolver _inner = new();

    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) =>
        type == typeof(Person) ? _inner.GetTypeInfo(type, options) : null;
}

